 37→@Service
 38→@Slf4j
 39→public class DefaultAppUploadDataServiceImpl implements ThirdAppUploadDataService {
 40→    @Resource
 41→    ISpaceNodeService iSpaceNodeService;
 42→
 43→    @Resource
 44→    TreeNodeTemplate treeNodeTemplate;
 45→
 46→    @Resource
 47→    SpaceNodeMapper spaceNodeMapper;
 48→
 49→    @Resource
 50→    WebSocketHandler webSocketHandler;
 51→
 52→    @Resource
 53→    ThirdAppUploadUpdateAsyncService thirdAppUploadUpdateAsyncService;
 54→
 55→    @Resource
 56→    ObjectMapper objectMapper;
 57→
 58→    @Resource
 59→    SpaceNodeUserRoleCacheQueryManager spaceNodeUserRoleCacheQueryManager;
 60→
 61→    @Autowired(required = false)
 62→    private RagDocNotifyPublisher ragDocNotifyPublisher;
 63→
 64→    @Value("${mq.enabled:true}")
 65→    private boolean mqEnabled;
 66→
 67→    @Override
 68→    public UploadDataIdTypeEnum supportedAppType() {
 69→        return UploadDataIdTypeEnum.Default;
 70→    }
 71→
 72→    @Override
 73→    public void uploadUpdateTime(String params) {
 74→        log.info("接收到更新参数{}", params);
 75→        if (mqEnabled) {
 76→            thirdAppUploadUpdateAsyncService.enqueueWithDedup(params);
 77→            return;
 78→        }
 79→        doUploadUpdateTime(params);
 80→    }
 81→
 82→    public void doUploadUpdateTime(String params) {
 83→        ThirdAppUploadUpdateParam param = JSON.parseObject(params, ThirdAppUploadUpdateParam.class);
 84→        log.info("json解析后的参数{}", param);
 85→        String appId = param == null ? null : param.getAppId();
 86→        String updateTime = param == null ? null : param.getUpdateTime();
 87→
 88→        if (appId == null || updateTime == null || appId.isBlank() || updateTime.isBlank()) {
 89→            throw new BusinessException("Missing appId and updateTime parameter");
 90→        }
 91→
 92→        LocalDateTime updateDateTime = parseDateTime(updateTime);
 93→
 94→        // 根据appId获取到对应的node数据
 95→        List<SpaceNodeEntity> spaceNodeEntityList = iSpaceNodeService.listByAppSpaceNodeIds(List.of(appId));
 96→        // 根据node数据获取父node数据
 97→        List<NodeEntity> nodeEntityList = treeNodeTemplate.getParentPathNodesByRelIds(spaceNodeEntityList.stream().
 98→                map(SpaceNodeEntity::getId).collect(Collectors.toList()));
 99→        List<Long> allRelNodeEntityIds = nodeEntityList.stream().map(NodeEntity::getRelId).toList();
100→        // 获取space
101→        List<SpaceNodeEntity> allSpaceNodeEntityList = iSpaceNodeService.listByIdsIncludeDeleted(allRelNodeEntityIds);
102→        allSpaceNodeEntityList.forEach(spaceNodeEntity -> {
103→            spaceNodeEntity.setUpdatedAt(updateDateTime);
104→            spaceNodeMapper.updateNodeTime(spaceNodeEntity.getId(), updateDateTime);
105→        });
106→        List<SpaceNodeForWebSocketVo> voList = allSpaceNodeEntityList.stream()
107→                .map(SpaceNodeForWebSocketVo::from)
108→                .toList();
109→
110→        WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.UPDATE_FILE_TIME.getType())
111→                        .message("更新时间").status(200).data(voList).build();
112→        String msg;
113→        try {
114→            msg = objectMapper.writeValueAsString(webSocketResponseModel);
115→        } catch (JsonProcessingException e) {
116→            throw new BusinessException("WebSocket序列化失败", e);
117→        }
118→        List<Long> spaceNodeIds = allSpaceNodeEntityList.stream().map(SpaceNodeEntity::getId).toList();
119→        List<Long> userIds = spaceNodeUserRoleCacheQueryManager.listUserIdsBySpaceNodeIdsAndMinRole(spaceNodeIds, NodeRoleLevel.READER);
120→        // 通知 rag-doc-server 重新索引变动的节点（与 WebSocket 推送无关，独立执行）
121→        if (ragDocNotifyPublisher != null) {
122→            for (SpaceNodeEntity spaceNode : spaceNodeEntityList) {
123→                ragDocNotifyPublisher.publishDocChange(spaceNode);
124→            }
125→        }
126→
127→        if (userIds.isEmpty()) {
128→            log.warn("未找到相关节点权限用户，跳过WebSocket推送");
129→            return;
130→        }
131→        webSocketHandler.sendUsersToWebSocketClient(msg, userIds);
132→
133→    }
134→
135→    private LocalDateTime parseDateTime(String updateTime) {
136→        // 把格式不正确的进行记录
137→        if (updateTime.length() != 19) {
138→            log.error("上传时间格式错误{}", updateTime);
139→        }
140→        DateTimeFormatter formatter = new DateTimeFormatterBuilder()
141→                .appendPattern("yyyy-MM-dd")
142→                .optionalStart()
143→                .appendPattern(" HH:mm")
144→                .optionalStart()
145→                .appendPattern(":ss")
146→                .optionalEnd()
147→                .optionalEnd()
148→                .parseDefaulting(ChronoField.HOUR_OF_DAY, 0)
149→                .parseDefaulting(ChronoField.MINUTE_OF_HOUR, 0)
150→                .parseDefaulting(ChronoField.SECOND_OF_MINUTE, 0)
151→                .toFormatter();
152→
153→        return LocalDateTime.parse(updateTime, formatter);
154→    }
155→
156→}
