 34→@Slf4j
 35→@Service
 36→public class DocSubscriptionNotifyManagerImpl implements DocSubscriptionNotifyManager {
 37→
 38→    private static final String LOG_PREFIX = "[订阅通知]";
 39→    /** 单次推送节流 key 前缀，TTL 300s，防止同一文档对同一用户重复推送 */
 40→    private static final String THROTTLE_KEY_PREFIX = "subscription:throttle:";
 41→    /** IM 发送次数计数 key 前缀，TTL 300s，超过 10 次聚合推送 */
 42→    private static final String IM_COUNT_KEY_PREFIX = "subscription:im_count:";
 43→    private static final long THROTTLE_TTL_SECONDS = 300L;
 44→    private static final long IM_COUNT_TTL_SECONDS = 300L;
 45→    private static final long IM_COUNT_AGGREGATE_THRESHOLD = 10L;
 46→
 47→    @Value("${subscription.im.channel:none}")
 48→    private String imChannel;
 49→
 50→    @Value("${subscription.collabspace.url:}")
 51→    private String collabspaceUrl;
 52→
 53→    @Resource
 54→    private IDocSubscriptionService docSubscriptionService;
 55→
 56→    @Resource
 57→    private IDocSubscriptionNotificationService docSubscriptionNotificationService;
 58→
 59→    @Resource
 60→    private SpaceNodeUserRoleCacheQueryManager spaceNodeUserRoleCacheQueryManager;
 61→
 62→    @Resource
 63→    private WebSocketHandler webSocketHandler;
 64→
 65→    @Resource
 66→    private StringRedisTemplate stringRedisTemplate;
 67→
 68→    @Resource
 69→    private ObjectMapper objectMapper;
 70→
 71→    @Override
 72→    public void handleDocUpdate(DocSubscriptionNotifyMsg msg) {
 73→        Long spaceNodeId = msg.getSpaceNodeId();
 74→        String spaceNodeName = msg.getSpaceNodeName();
 75→        Long operatorId = msg.getOperatorId();
 76→        String traceId = msg.getTraceId();
 77→
 78→        // 1. 查询订阅该文档的所有用户
 79→        List<DocSubscriptionEntity> subscribers = docSubscriptionService.listBySpaceNodeId(spaceNodeId);
 80→        if (subscribers.isEmpty()) {
 81→            log.info("{} 无订阅者，跳过 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
 82→            return;
 83→        }
 84→
 85→        // 2. 过滤掉操作人自身
 86→        Set<Long> subscriberIds = subscribers.stream()
 87→                .map(DocSubscriptionEntity::getUserId)
 88→                .collect(Collectors.toSet());
 89→        if (operatorId != null) {
 90→            subscriberIds.remove(operatorId);
 91→        }
 92→        if (subscriberIds.isEmpty()) {
 93→            log.info("{} 过滤操作人后无订阅者 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
 94→            return;
 95→        }
 96→
 97→        // 3. 权限校验：取与有读权限用户的交集
 98→        List<Long> permittedUserIds = spaceNodeUserRoleCacheQueryManager
 99→                .listUserIdsBySpaceNodeIdsAndMinRole(List.of(spaceNodeId), NodeRoleLevel.READER);
100→        Set<Long> permittedSet = new HashSet<>(permittedUserIds);
101→        subscriberIds.retainAll(permittedSet);
102→        if (subscriberIds.isEmpty()) {
103→            log.info("{} 权限校验后无目标用户 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
104→            return;
105→        }
106→
107→        // 4. 逐用户处理：节流 + 保存通知 + IM 推送
108→        List<Long> notifiedUserIds = new ArrayList<>();
109→        for (Long userId : subscriberIds) {
110→            // 4a. Redis 节流：同一文档同一用户 300s 内只推一次
111→            String throttleKey = THROTTLE_KEY_PREFIX + spaceNodeId + ":" + userId;
112→            Boolean isFirstPush = stringRedisTemplate.opsForValue()
113→                    .setIfAbsent(throttleKey, "1", THROTTLE_TTL_SECONDS, TimeUnit.SECONDS);
114→            if (!Boolean.TRUE.equals(isFirstPush)) {
115→                log.debug("{} 节流跳过 spaceNodeId={} userId={}", LOG_PREFIX, spaceNodeId, userId);
116→                continue;
117→            }
118→
119→            // 4b. 保存通知记录
120→            DocSubscriptionNotificationEntity notification = DocSubscriptionNotificationEntity.builder()
121→                    .userId(userId)
122→                    .spaceNodeId(spaceNodeId)
123→                    .spaceNodeName(spaceNodeName)
124→                    .isRead(0)
125→                    .build();
126→            docSubscriptionNotificationService.save(notification);
127→
128→            // 4c. IM 推送计数与分发
129→            String imCountKey = IM_COUNT_KEY_PREFIX + userId;
130→            Long imCount = stringRedisTemplate.opsForValue().increment(imCountKey);
131→            if (imCount == null) {
132→                imCount = 1L;
133→            }
134→            if (imCount == 1L) {
135→                // 首次计数，设置 TTL
136→                stringRedisTemplate.expire(imCountKey, IM_COUNT_TTL_SECONDS, TimeUnit.SECONDS);
137→            }
138→
139→            if (imCount > IM_COUNT_AGGREGATE_THRESHOLD) {
140→                // 超过 10 次，跳过单独推送（聚合消息已在第 10 次发出）
141→                log.debug("{} IM 计数超阈值，跳过单独推送 userId={} count={}", LOG_PREFIX, userId, imCount);
142→            } else if (imCount.equals(IM_COUNT_AGGREGATE_THRESHOLD)) {
143→                // 第 10 次：发送聚合提示消息
144→                sendAggregateImMsg(userId, traceId);
145→            } else {
146→                // 1~9 次：发送正常单条消息
147→                sendNormalImMsg(userId, spaceNodeId, spaceNodeName, traceId);
148→            }
149→
150→            notifiedUserIds.add(userId);
151→        }
152→
153→        // 5. WebSocket 推送给所有命中用户
154→        if (!notifiedUserIds.isEmpty()) {
155→            pushViaWebSocket(notifiedUserIds, spaceNodeId, spaceNodeName, traceId);
156→        }
157→
158→        log.info("{} 处理完成 spaceNodeId={} notifiedCount={} traceId={}",
159→                LOG_PREFIX, spaceNodeId, notifiedUserIds.size(), traceId);
160→    }
161→
162→    /**
163→     * WebSocket 推送订阅更新事件
164→     */
165→    private void pushViaWebSocket(List<Long> userIds, Long spaceNodeId, String spaceNodeName, String traceId) {
166→        try {
167→            Map<String, Object> payload = new HashMap<>(4);
168→            payload.put("spaceNodeId", String.valueOf(spaceNodeId));
169→            payload.put("spaceNodeName", spaceNodeName);
170→            WebSocketResponseModel responseModel = WebSocketResponseModel.builder()
171→                    .message(MessageTypeEnum.SUBSCRIPTION_UPDATE.getDesc())
172→                    .status(200)
173→                    .type(MessageTypeEnum.SUBSCRIPTION_UPDATE.getType())
174→                    .data(payload)
175→                    .build();
176→            String wsMsg = objectMapper.writeValueAsString(responseModel);
177→            int sent = webSocketHandler.sendUsersToWebSocketClient(wsMsg, userIds);
178→            log.info("{} WebSocket 推送完成 spaceNodeId={} targetCount={} actualSent={} traceId={}",
179→                    LOG_PREFIX, spaceNodeId, userIds.size(), sent, traceId);
180→        } catch (Exception e) {
181→            log.error("{} WebSocket 推送失败 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId, e);
182→        }
183→    }
184→
185→    /**
186→     * 发送正常 IM 单条通知
187→     * TODO: implement in Task 8
188→     */
189→    private void sendNormalImMsg(Long userId, Long spaceNodeId, String spaceNodeName, String traceId) {
190→        log.info("{} [TODO-Task8] 发送 IM 单条通知 channel={} userId={} spaceNodeId={} traceId={}",
191→                LOG_PREFIX, imChannel, userId, spaceNodeId, traceId);
192→        // TODO: implement in Task 8
193→    }
194→
195→    /**
196→     * 发送 IM 聚合提示消息（当短时间内通知数超过阈值时）
197→     * TODO: implement in Task 8
198→     */
199→    private void sendAggregateImMsg(Long userId, String traceId) {
200→        log.info("{} [TODO-Task8] 发送 IM 聚合通知 channel={} userId={} traceId={}",
201→                LOG_PREFIX, imChannel, userId, traceId);
202→        // TODO: implement in Task 8
203→    }
