205→    @Override
206→    public IPage<SubscriptionNotificationVo> listNotifications(Long userId, NotificationQueryRo ro) {
207→        IPage<DocSubscriptionNotificationEntity> entityPage = docSubscriptionNotificationService
208→                .pageByUserId(userId, ro.getIsRead(), ro.getPageNum(), ro.getPageSize());
209→
210→        List<SubscriptionNotificationVo> voList = entityPage.getRecords().stream()
211→                .map(entity -> SubscriptionNotificationVo.builder()
212→                        .id(entity.getId())
213→                        .spaceNodeId(entity.getSpaceNodeId())
214→                        .spaceNodeName(entity.getSpaceNodeName())
215→                        .isRead(entity.getIsRead())
216→                        .createdAt(entity.getCreatedAt())
217→                        .build())
218→                .collect(Collectors.toList());
219→
220→        IPage<SubscriptionNotificationVo> resultPage = new Page<>(entityPage.getCurrent(), entityPage.getSize(), entityPage.getTotal());
221→        resultPage.setRecords(voList);
222→        return resultPage;
223→    }
