226→    public void markRead(Long userId, List<Long> notificationIds) {
227→        docSubscriptionNotificationService.markReadByIds(userId, notificationIds);
228→    }
229→
230→    @Override
231→    public void markAllRead(Long userId) {
232→        docSubscriptionNotificationService.markAllReadByUserId(userId);
233→    }
234→
235→    @Override
236→    public long countUnread(Long userId) {
237→        return docSubscriptionNotificationService.countUnreadByUserId(userId);
238→    }
239→}
