13→import java.util.Map;
14→
15→/**
16→ * Knock 消息服务，通过 OA Channel 发送机器人消息
17→ */
18→@Slf4j
19→@Service
20→public class KnockService {
21→
22→    /** 机器人消息签名key */
23→    private static final String SIGN_KEY_ROBOT = "knock_send_robot_msg";
24→
25→    /** 机器人名称：Yottatable */
26→    private static final String ROBOT_NAME = "yotta-Yottatable";
27→
28→    @Resource
29→    private OAChnService oaChnService;
30→
31→    @Value("${oa.chn.host}")
32→    private String oaChnHost;
33→
34→    @Value("${oa.chn.client-id}")
35→    private String clientId;
36→
37→    @Value("${oa.chn.client-secret}")
38→    private String clientSecret;
39→
40→    /**
41→     * 通过 Yottatable 机器人发送富文本消息给指定用户
42→     *
43→     * @param nicknames 接收人昵称列表
44→     * @param title     消息标题
45→     * @param content   消息内容
46→     */
47→    public void sendRobotRichMsg(Collection<String> nicknames, String title, String content) {
48→        Map<String, Object> body = new HashMap<>();
49→        body.put("nicknames", nicknames);
50→        body.put("robot_name", ROBOT_NAME);
51→        // 富文本消息体，Knock要求<>在内层JSON中以\u003c \u003e形式传递
52→        Map<String, String> richContent = new HashMap<>();
53→        richContent.put("title", title);
54→        richContent.put("content", content);
55→        String richContentJson = JSONUtil.toJsonStr(richContent)
56→                .replace("<", "\\u003c")
57→                .replace(">", "\\u003e");
58→        body.put("content", richContentJson);
59→        body.put("msg_type", "MSG_TYPE_RICH_CARD");
60→
61→        String payload = JSONUtil.toJsonStr(body);
62→        String sign = oaChnService.getSign(clientId, SIGN_KEY_ROBOT, payload, clientSecret);
63→
64→        OAChnSendRequest request = OAChnSendRequest.builder()
65→                .clientId(clientId)
66→                .key(SIGN_KEY_ROBOT)
67→                .payload(payload)
68→                .sign(sign)
69→                .build();
70→
71→        String url = oaChnHost + "/third-api/request";
72→        log.info("[lbl][2087-消息推送][Knock][SEND] 发送富文本消息, url={}, robotName={}, nicknameCount={}, nicknames={}, title={}, contentLength={}",
73→                url, ROBOT_NAME, nicknames.size(), nicknames, title, content);
74→        log.info("[lbl][2087-消息推送][Knock][SEND] 请求详情: clientId={}, key={}, payloadLength={}, sign={}", clientId, SIGN_KEY_ROBOT, payload, sign);
75→        Object result = oaChnService.send(request);
76→        log.info("[lbl][2087-消息推送][Knock][SEND] 响应: {}", JSONUtil.toJsonStr(result));
77→    }
78→}
