 25→@Slf4j
 26→@Service
 27→public class AnnouncementPushService {
 28→
 29→    @Resource
 30→    private KnockService knockService;
 31→
 32→    @Resource
 33→    private IApitableGrpcClientService apitableGrpcClientService;
 34→
 35→    @Resource
 36→    private MattermostMessageFeign mattermostMessageFeign;
