 46→
 47→    /**
 48→     * 公告发布后推送到 Knock + MM
 49→     */
 50→    public void pushAnnouncement(AnnouncementEntity announcement) {
 51→        log.info("[lbl][2087-消息推送][Announcement][PUSH] 开始推送公告到Knock+MM, id={}, title={}", announcement.getId(), announcement.getTitle());
 52→
 53→        pushToKnock(announcement);
 54→//        pushToMm(announcement);
 55→
 56→        log.info("[lbl][2087-消息推送][Announcement][PUSH] 公告推送完成, id={}", announcement.getId());
 57→    }
 58→
 59→    /**
 60→     * 推送到 Knock（通过 Yottatable 机器人发送富文本消息给所有用户）
 61→     */
 62→    private void pushToKnock(AnnouncementEntity announcement) {
 63→        try {
 64→            String knockContent = AnnouncementFormatConverter.toKnockMarkdown(announcement.getContent());
 65→            String title = announcement.getTitle();
 66→            if (StrUtil.isBlank(title)) {
 67→                title = "CollabSpace升级公告";
 68→            }
 69→            // 通过gRPC获取所有有效用户昵称
 70→            List<String> allNickNames = apitableGrpcClientService.getAllValidUsers(-1L).stream()
 71→                    .map(UserSimpleInfoVo::getNickName)
 72→                    .filter(StrUtil::isNotBlank)
