    Long imCount = stringRedisTemplate.opsForValue().increment(imCountKey);
    if (imCount == null) {
        imCount = 1L;
    }
    if (imCount == 1L) {
        // 首次计数，设置 TTL
        stringRedisTemplate.expire(imCountKey, IM_COUNT_TTL_SECONDS, TimeUnit.SECONDS);
    }

