/**
 * 发送正常 IM 单条通知（1~9 次）
 * 消息内容：您订阅的文档 <docName> 有新的版本了，点此直达文档：<url>
 */
private void sendNormalImMsg(Long userId, Long spaceNodeId, String spaceNodeName,
                             Map<Long, UserSimpleInfoVo> userInfoMap, String traceId) {
    String docUrl = collabspaceUrl + "/#/view-node/" + spaceNodeId;
    String title = "CollabSpace通知";
    String content = "【CollabSpace通知】您订阅的文档 " + spaceNodeName + " 有新的版本了，点此直达文档：" + docUrl;
    log.info("{} 发送 IM 单条通知 channel={} userId={} spaceNodeId={} traceId={}",
            LOG_PREFIX, imChannel, userId, spaceNodeId, traceId);
    sendImMsg(userId, title, content, userInfoMap, traceId);
}

/**
 * 发送 IM 聚合提示消息（第 10 次时触发）
 * 消息内容：你关注的多个文档都有更新，请到 collabspace 查看
 */
private void sendAggregateImMsg(Long userId, Map<Long, UserSimpleInfoVo> userInfoMap, String traceId) {
    String title = "CollabSpace通知";
    String content = "你关注的多个文档都有更新，请到 collabspace 查看：" + collabspaceUrl;
    log.info("{} 发送 IM 聚合通知 channel={} userId={} traceId={}",
            LOG_PREFIX, imChannel, userId, traceId);
    sendImMsg(userId, title, content, userInfoMap, traceId);
}

/**
 * 根据配置的 channel 向指定用户发送 IM 消息（knock 或 mm）
 */
private void sendImMsg(Long userId, String title, String content,
                       Map<Long, UserSimpleInfoVo> userInfoMap, String traceId) {
    if ("none".equalsIgnoreCase(imChannel) || StrUtil.isBlank(imChannel)) {
        log.info("{} IM channel=none，跳过推送 userId={} traceId={}", LOG_PREFIX, userId, traceId);
        return;
    }
    UserSimpleInfoVo userInfo = userInfoMap.get(userId);
    if (userInfo == null) {
        log.warn("{} 用户信息不存在，跳过 IM 推送 userId={} traceId={}", LOG_PREFIX, userId, traceId);
        return;
    }
    if ("knock".equalsIgnoreCase(imChannel)) {
        sendViaKnock(userInfo, title, content, traceId);
    } else if ("mm".equalsIgnoreCase(imChannel)) {
        sendViaMm(userInfo, content, traceId);
    } else {
        log.warn("{} 未知 IM channel={}, 跳过推送 userId={} traceId={}", LOG_PREFIX, imChannel, userId, traceId);
    }
}

/**
 * 通过 Knock 机器人发送富文本消息给指定用户
 */
private void sendViaKnock(UserSimpleInfoVo userInfo, String title, String content, String traceId) {
    try {
        String nickName = userInfo.getNickName();
        if (StrUtil.isBlank(nickName)) {
            log.warn("{} Knock 推送跳过，用户昵称为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
            return;
        }
        // 测试环境只打日志不实际发送
        if (constProperties.isTestServer()) {
            log.info("{} [测试环境-不发送] Knock推送 userId={} nickName={} title={} traceId={}",
                    LOG_PREFIX, userInfo.getId(), nickName, title, traceId);
            return;
        }
        knockService.sendRobotRichMsg(List.of(nickName), title, content);
        log.info("{} Knock推送成功 userId={} nickName={} traceId={}", LOG_PREFIX, userInfo.getId(), nickName, traceId);
    } catch (Exception e) {
        log.error("{} Knock推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
    }
}

/**
 * 通过 MM 机器人发送私信给指定用户
 */
private void sendViaMm(UserSimpleInfoVo userInfo, String content, String traceId) {
    try {
        String email = userInfo.getEmail();
        if (StrUtil.isBlank(email)) {
            log.warn("{} MM 推送跳过，用户邮箱为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
            return;
        }
        String botToken = mattermostProperties.getXcollabspaceBotToken();
        String botUserId = mattermostProperties.getXcollabspaceBotUserId();
        if (StrUtil.isBlank(botToken) || StrUtil.isBlank(botUserId)) {
            log.warn("{} MM 推送跳过，botToken 或 botUserId 未配置 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
            return;
        }
        String authToken = "Bearer " + botToken;

        // 查询 MM 用户 ID
        MattermostUserInfoResp mmUser = mattermostMessageFeign.getUserByEmail(authToken, email);
        if (mmUser == null || StrUtil.isBlank(mmUser.getId())) {
            log.warn("{} MM 推送跳过，用户在 MM 中不存在 userId={} email={} traceId={}",
                    LOG_PREFIX, userInfo.getId(), email, traceId);
            return;
        }

        // 测试环境只打日志不实际发送
        if (constProperties.isTestServer()) {
            log.info("{} [测试环境-不发送] MM推送 userId={} email={} mmUserId={} traceId={}",
                    LOG_PREFIX, userInfo.getId(), email, mmUser.getId(), traceId);
            return;
        }

        // 创建私信频道
        MattermostDirectChannelResp channel = mattermostMessageFeign.createDirectMessageChannel(
                authToken, List.of(mmUser.getId(), botUserId));
        if (channel == null || StrUtil.isBlank(channel.getId())) {
            log.warn("{} MM 推送跳过，创建私信频道失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
            return;
        }

        // 发送消息
        MattermostPostReq postReq = MattermostPostReq.builder()
                .channelId(channel.getId())
                .message(content)
                .build();
        mattermostMessageFeign.createPost(authToken, false, postReq);
        log.info("{} MM推送成功 userId={} email={} channelId={} traceId={}",
                LOG_PREFIX, userInfo.getId(), email, channel.getId(), traceId);
    } catch (Exception e) {
        log.error("{} MM推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
    }
}

