 96→    @Override
 97→    public void handleDocUpdate(DocSubscriptionNotifyMsg msg) {
 98→        Long spaceNodeId = msg.getSpaceNodeId();
 99→        String spaceNodeName = msg.getSpaceNodeName();
100→        Long operatorId = msg.getOperatorId();
101→        String traceId = msg.getTraceId();
102→
103→        // 1. 查询订阅该文档的所有用户
104→        List<DocSubscriptionEntity> subscribers = docSubscriptionService.listBySpaceNodeId(spaceNodeId);
105→        if (subscribers.isEmpty()) {
106→            log.info("{} 无订阅者，跳过 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
107→            return;
108→        }
109→
110→        // 2. 过滤掉操作人自身
111→        Set<Long> subscriberIds = subscribers.stream()
112→                .map(DocSubscriptionEntity::getUserId)
113→                .collect(Collectors.toSet());
114→        if (operatorId != null) {
115→            subscriberIds.remove(operatorId);
116→        }
117→        if (subscriberIds.isEmpty()) {
118→            log.info("{} 过滤操作人后无订阅者 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
119→            return;
120→        }
121→
122→        // 3. 权限校验：取与有读权限用户的交集
123→        List<Long> permittedUserIds = spaceNodeUserRoleCacheQueryManager
124→                .listUserIdsBySpaceNodeIdsAndMinRole(List.of(spaceNodeId), NodeRoleLevel.READER);
125→        Set<Long> permittedSet = new HashSet<>(permittedUserIds);
126→        subscriberIds.retainAll(permittedSet);
127→        if (subscriberIds.isEmpty()) {
128→            log.info("{} 权限校验后无目标用户 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
129→            return;
130→        }
131→
132→        // 4. 批量获取用户信息，避免循环内逐个查询（用于 IM 推送）
133→        Map<Long, UserSimpleInfoVo> userInfoMap = new HashMap<>();
134→        try {
135→            List<UserSimpleInfoVo> allUsers = apitableGrpcClientService.getAllValidUsers(-1L);
136→            for (UserSimpleInfoVo u : allUsers) {
137→                if (u.getId() != null) {
138→                    userInfoMap.put(u.getId(), u);
139→                }
140→            }
141→        } catch (Exception e) {
142→            log.warn("{} 批量获取用户信息失败，IM 推送将跳过 traceId={}", LOG_PREFIX, traceId, e);
143→        }
144→
145→        // 5. 逐用户处理：节流 + 保存通知 + IM 推送
146→        List<Long> notifiedUserIds = new ArrayList<>();
147→        for (Long userId : subscriberIds) {
148→            // 5a. Redis 节流：同一文档同一用户 300s 内只推一次
149→            String throttleKey = THROTTLE_KEY_PREFIX + spaceNodeId + ":" + userId;
150→            Boolean isFirstPush = stringRedisTemplate.opsForValue()
151→                    .setIfAbsent(throttleKey, "1", THROTTLE_TTL_SECONDS, TimeUnit.SECONDS);
152→            if (!Boolean.TRUE.equals(isFirstPush)) {
153→                log.debug("{} 节流跳过 spaceNodeId={} userId={}", LOG_PREFIX, spaceNodeId, userId);
154→                continue;
155→            }
156→
157→            // 5b. 保存通知记录
158→            DocSubscriptionNotificationEntity notification = DocSubscriptionNotificationEntity.builder()
159→                    .userId(userId)
160→                    .spaceNodeId(spaceNodeId)
161→                    .spaceNodeName(spaceNodeName)
162→                    .isRead(0)
163→                    .build();
164→            docSubscriptionNotificationService.save(notification);
165→
166→            // 5c. IM 推送计数与分发
167→            String imCountKey = IM_COUNT_KEY_PREFIX + userId;
168→            Long imCount = stringRedisTemplate.opsForValue().increment(imCountKey);
169→            if (imCount == null) {
170→                imCount = 1L;
171→            }
172→            if (imCount == 1L) {
173→                // 首次计数，设置 TTL
174→                stringRedisTemplate.expire(imCountKey, IM_COUNT_TTL_SECONDS, TimeUnit.SECONDS);
175→            }
176→
177→            if (imCount > IM_COUNT_AGGREGATE_THRESHOLD) {
178→                // 超过 10 次，跳过单独推送（聚合消息已在第 10 次发出）
179→                log.debug("{} IM 计数超阈值，跳过单独推送 userId={} count={}", LOG_PREFIX, userId, imCount);
180→            } else if (imCount.equals(IM_COUNT_AGGREGATE_THRESHOLD)) {
181→                // 第 10 次：发送聚合提示消息
182→                sendAggregateImMsg(userId, userInfoMap, traceId);
183→            } else {
184→                // 1~9 次：发送正常单条消息
185→                sendNormalImMsg(userId, spaceNodeId, spaceNodeName, userInfoMap, traceId);
186→            }
187→
188→            notifiedUserIds.add(userId);
189→        }
190→
191→        // 6. WebSocket 推送给所有命中用户
192→        if (!notifiedUserIds.isEmpty()) {
193→            pushViaWebSocket(notifiedUserIds, spaceNodeId, spaceNodeName, traceId);
194→        }
195→
196→        log.info("{} 处理完成 spaceNodeId={} notifiedCount={} traceId={}",
197→                LOG_PREFIX, spaceNodeId, notifiedUserIds.size(), traceId);
198→    }
