200→    /**
201→     * WebSocket 推送订阅更新事件
202→     */
203→    private void pushViaWebSocket(List<Long> userIds, Long spaceNodeId, String spaceNodeName, String traceId) {
204→        try {
205→            Map<String, Object> payload = new HashMap<>(4);
206→            payload.put("spaceNodeId", String.valueOf(spaceNodeId));
207→            payload.put("spaceNodeName", spaceNodeName);
208→            WebSocketResponseModel responseModel = WebSocketResponseModel.builder()
209→                    .message(MessageTypeEnum.SUBSCRIPTION_UPDATE.getDesc())
210→                    .status(200)
211→                    .type(MessageTypeEnum.SUBSCRIPTION_UPDATE.getType())
212→                    .data(payload)
213→                    .build();
214→            String wsMsg = objectMapper.writeValueAsString(responseModel);
215→            int sent = webSocketHandler.sendUsersToWebSocketClient(wsMsg, userIds);
216→            log.info("{} WebSocket 推送完成 spaceNodeId={} targetCount={} actualSent={} traceId={}",
217→                    LOG_PREFIX, spaceNodeId, userIds.size(), sent, traceId);
218→        } catch (Exception e) {
219→            log.error("{} WebSocket 推送失败 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId, e);
220→        }
221→    }
