249→    /**
250→     * 根据配置的 channel 向指定用户发送 IM 消息（knock 或 mm）
251→     */
252→    private void sendImMsg(Long userId, String title, String content,
253→                           Map<Long, UserSimpleInfoVo> userInfoMap, String traceId) {
254→        if ("none".equalsIgnoreCase(imChannel) || StrUtil.isBlank(imChannel)) {
255→            log.info("{} IM channel=none，跳过推送 userId={} traceId={}", LOG_PREFIX, userId, traceId);
256→            return;
257→        }
258→        UserSimpleInfoVo userInfo = userInfoMap.get(userId);
259→        if (userInfo == null) {
260→            log.warn("{} 用户信息不存在，跳过 IM 推送 userId={} traceId={}", LOG_PREFIX, userId, traceId);
261→            return;
262→        }
263→        if ("knock".equalsIgnoreCase(imChannel)) {
264→            sendViaKnock(userInfo, title, content, traceId);
265→        } else if ("mm".equalsIgnoreCase(imChannel)) {
266→            sendViaMm(userInfo, content, traceId);
267→        } else {
268→            log.warn("{} 未知 IM channel={}, 跳过推送 userId={} traceId={}", LOG_PREFIX, imChannel, userId, traceId);
269→        }
270→    }
