272→    /**
273→     * 通过 Knock 机器人发送富文本消息给指定用户
274→     */
275→    private void sendViaKnock(UserSimpleInfoVo userInfo, String title, String content, String traceId) {
276→        try {
277→            String nickName = userInfo.getNickName();
278→            if (StrUtil.isBlank(nickName)) {
279→                log.warn("{} Knock 推送跳过，用户昵称为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
280→                return;
281→            }
282→            // 测试环境只打日志不实际发送
283→            if (constProperties.isTestServer()) {
284→                log.info("{} [测试环境-不发送] Knock推送 userId={} nickName={} title={} traceId={}",
285→                        LOG_PREFIX, userInfo.getId(), nickName, title, traceId);
286→                return;
287→            }
288→            knockService.sendRobotRichMsg(List.of(nickName), title, content);
289→            log.info("{} Knock推送成功 userId={} nickName={} traceId={}", LOG_PREFIX, userInfo.getId(), nickName, traceId);
290→        } catch (Exception e) {
291→            log.error("{} Knock推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
292→        }
293→    }
