295→    /**
296→     * 通过 MM 机器人发送私信给指定用户
297→     */
298→    private void sendViaMm(UserSimpleInfoVo userInfo, String content, String traceId) {
299→        try {
300→            String email = userInfo.getEmail();
301→            if (StrUtil.isBlank(email)) {
302→                log.warn("{} MM 推送跳过，用户邮箱为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
303→                return;
304→            }
305→            String botToken = mattermostProperties.getXcollabspaceBotToken();
306→            String botUserId = mattermostProperties.getXcollabspaceBotUserId();
307→            if (StrUtil.isBlank(botToken) || StrUtil.isBlank(botUserId)) {
308→                log.warn("{} MM 推送跳过，botToken 或 botUserId 未配置 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
309→                return;
310→            }
311→            String authToken = "Bearer " + botToken;
312→
313→            // 查询 MM 用户 ID
314→            MattermostUserInfoResp mmUser = mattermostMessageFeign.getUserByEmail(authToken, email);
315→            if (mmUser == null || StrUtil.isBlank(mmUser.getId())) {
316→                log.warn("{} MM 推送跳过，用户在 MM 中不存在 userId={} email={} traceId={}",
317→                        LOG_PREFIX, userInfo.getId(), email, traceId);
318→                return;
319→            }
320→
321→            // 测试环境只打日志不实际发送
322→            if (constProperties.isTestServer()) {
323→                log.info("{} [测试环境-不发送] MM推送 userId={} email={} mmUserId={} traceId={}",
324→                        LOG_PREFIX, userInfo.getId(), email, mmUser.getId(), traceId);
325→                return;
326→            }
327→
328→            // 创建私信频道
329→            MattermostDirectChannelResp channel = mattermostMessageFeign.createDirectMessageChannel(
330→                    authToken, List.of(mmUser.getId(), botUserId));
331→            if (channel == null || StrUtil.isBlank(channel.getId())) {
332→                log.warn("{} MM 推送跳过，创建私信频道失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
333→                return;
334→            }
335→
336→            // 发送消息
337→            MattermostPostReq postReq = MattermostPostReq.builder()
338→                    .channelId(channel.getId())
339→                    .message(content)
340→                    .build();
341→            mattermostMessageFeign.createPost(authToken, false, postReq);
342→            log.info("{} MM推送成功 userId={} email={} channelId={} traceId={}",
343→                    LOG_PREFIX, userInfo.getId(), email, channel.getId(), traceId);
344→        } catch (Exception e) {
345→            log.error("{} MM推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
346→        }
347→    }
